프로젝트 구조와 컨벤션을 충분히 파악했습니다. 이제 프로필 수정 API 인터페이스를 설계하겠습니다.

---

# 프로필 수정 API 인터페이스 설계

## 1. 현재 스키마 분석

프로젝트는 `.claude/skills/` 스킬 파일 외에 실제 소스 코드가 없는 초기 상태입니다. 따라서 아래 설계는 프로젝트 컨벤션(graphql-skill, grpc-skill)을 기준으로 작성합니다.

---

## 2. GraphQL 스키마 설계

**파일 위치: `graphql/src/main/resources/graphql/profile.graphqls`**

```graphql
# --- Enum Types ---

enum Gender {
    MALE
    FEMALE
    OTHER
}

enum AppPurpose {
    SOCIAL      # 소셜 (친구 사귀기)
    DATING      # 데이팅 (연애)
    BOTH        # 둘 다
}

enum VoiceCallPreference {
    OPEN        # 누구나 통화 가능
    FRIENDS_ONLY # 친구만 통화 가능
    OFF         # 수신 거부
}

# --- Object Types ---

type Profile {
    userId: ID!
    nickname: String!
    birthDate: String!          # "YYYY-MM-DD" (ISO 8601)
    gender: Gender!
    bio: String                 # 자기소개 (nullable, 선택)
    profileImageUrl: String     # 프로필 사진 URL (nullable)
    interests: [String!]!       # 관심사 태그 목록
    purpose: AppPurpose!
    voiceCallPreference: VoiceCallPreference!
    updatedAt: String!
}

# --- Input Types ---

input UpdateProfileInput {
    nickname: String            # null이면 변경 안 함
    birthDate: String           # "YYYY-MM-DD"
    gender: Gender
    bio: String                 # 빈 문자열("")로 전송 시 삭제
    interests: [String!]        # null이면 변경 안 함, 빈 배열이면 전체 삭제
    purpose: AppPurpose
    voiceCallPreference: VoiceCallPreference
}

input UpdateProfileImageInput {
    profileImageUrl: String!    # S3/CDN URL (클라이언트에서 presigned URL로 업로드 후 전달)
}

# --- Mutations ---

extend type Mutation {
    updateProfile(input: UpdateProfileInput!): Profile!
    updateProfileImage(input: UpdateProfileImageInput!): Profile!
    deleteProfileImage: Profile!
}

# --- Queries ---

extend type Query {
    myProfile: Profile!
    userProfile(userId: ID!): Profile
}
```

---

## 3. gRPC Proto 설계

**파일 위치: `protobuf/src/main/proto/profile/profile.proto`**

```protobuf
syntax = "proto3";
package profile;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.profile";

// --- Enums ---

enum Gender {
    GENDER_UNSPECIFIED = 0;
    MALE = 1;
    FEMALE = 2;
    OTHER = 3;
}

enum AppPurpose {
    APP_PURPOSE_UNSPECIFIED = 0;
    SOCIAL = 1;
    DATING = 2;
    BOTH = 3;
}

enum VoiceCallPreference {
    VOICE_CALL_PREFERENCE_UNSPECIFIED = 0;
    OPEN = 1;
    FRIENDS_ONLY = 2;
    OFF = 3;
}

// --- Service ---

service ProfileService {
    rpc GetProfile(GetProfileRequest) returns (GetProfileResponse);
    rpc UpdateProfile(UpdateProfileRequest) returns (UpdateProfileResponse);
    rpc UpdateProfileImage(UpdateProfileImageRequest) returns (UpdateProfileImageResponse);
    rpc DeleteProfileImage(DeleteProfileImageRequest) returns (DeleteProfileImageResponse);
}

// --- Message: Profile ---

message Profile {
    string user_id = 1;
    string nickname = 2;
    string birth_date = 3;          // "YYYY-MM-DD"
    Gender gender = 4;
    optional string bio = 5;
    optional string profile_image_url = 6;
    repeated string interests = 7;
    AppPurpose purpose = 8;
    VoiceCallPreference voice_call_preference = 9;
    string updated_at = 10;
}

// --- GetProfile ---

message GetProfileRequest {
    string user_id = 1;
    string requester_id = 2;        // 조회 요청자 (본인 조회 vs 타인 조회 구분)
}

message GetProfileResponse {
    Profile profile = 1;
}

// --- UpdateProfile ---

message UpdateProfileRequest {
    string user_id = 1;
    optional string nickname = 2;
    optional string birth_date = 3;
    optional Gender gender = 4;
    optional string bio = 5;
    repeated string interests = 6;  // 빈 배열이면 전체 삭제
    bool interests_provided = 7;    // interests 필드가 실제로 전달됐는지 여부
    optional AppPurpose purpose = 8;
    optional VoiceCallPreference voice_call_preference = 9;
}

message UpdateProfileResponse {
    Profile profile = 1;
}

// --- UpdateProfileImage ---

message UpdateProfileImageRequest {
    string user_id = 1;
    string profile_image_url = 2;
}

message UpdateProfileImageResponse {
    Profile profile = 1;
}

// --- DeleteProfileImage ---

message DeleteProfileImageRequest {
    string user_id = 1;
}

message DeleteProfileImageResponse {
    Profile profile = 1;
}
```

