## 4. GraphQL Controller 스텁

**파일 위치: `graphql/src/main/kotlin/com/maum/backend/controller/profile/ProfileController.kt`**

```kotlin
@Controller
class ProfileController(
    private val profileService: ProfileService,
) {
    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun myProfile(
        @UserId userId: String,
    ): ProfileResponse {
        val response = profileService.getProfile(userId, requesterId = userId)
        return response.profile.toResponse()
    }

    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun userProfile(
        @UserId userId: String,
        @Argument userId: String,
    ): ProfileResponse? {
        val response = profileService.getProfile(targetUserId, requesterId = userId)
        return response.profile.toResponse()
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun updateProfile(
        @UserId userId: String,
        @Argument input: UpdateProfileInput,
    ): ProfileResponse {
        val response = profileService.updateProfile(userId, input)
        return response.profile.toResponse()
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun updateProfileImage(
        @UserId userId: String,
        @Argument input: UpdateProfileImageInput,
    ): ProfileResponse {
        val response = profileService.updateProfileImage(userId, input.profileImageUrl)
        return response.profile.toResponse()
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun deleteProfileImage(
        @UserId userId: String,
    ): ProfileResponse {
        val response = profileService.deleteProfileImage(userId)
        return response.profile.toResponse()
    }
}
```

